USE elder_care_system;

-- -----------------------------------------------------------
-- 角色表：管理系统内置角色（超级管理员/管理员/护工）
-- -----------------------------------------------------------


-- 根据客户护理级别生成客户实际护理项目记录。
-- 护理级别只是模板，护工端登记护理时读取的是 nursing_item_record。
    `customer_id`,
    `nursing_item_id`,
    `nursing_item_code`,
    `nursing_item_name`,
    `execution_cycle`,
    `execution_times`,
    `executed_times`,
    `purchasing_date`,
    `purchasing_times`,
    `expiration_date`,
    `status`,
    `del_flag`
)
SELECT
    c.customer_id,
    ni.nursing_item_id,
    ni.code,
    ni.nursing_item_name,
    ni.execution_cycle,
    ni.execution_times,
    0,
    c.check_in_date,
    1,
    '2027-01-01',
    '0',
    '0'
FROM `customer` c
INNER JOIN `nursing_level_item_mapping` m
    ON c.nursing_level_id = m.nursing_level_id
    AND m.del_flag = '0'
INNER JOIN `nursing_item` ni
    ON m.nursing_item_id = ni.nursing_item_id
    AND ni.del_flag = '0'
WHERE c.nursing_level_id IS NOT NULL
  AND c.del_flag = '0'
  AND c.history = '1'
  AND NOT EXISTS (
      SELECT 1
      FROM `nursing_item_record` existing
      WHERE existing.customer_id = c.customer_id
        AND existing.nursing_item_id = ni.nursing_item_id
        AND existing.del_flag = '0'
  );


